cd /app && node -e "
import { loadTheme, listThemes } from './src/themes/loader.js';

// List all themes
const themes = listThemes();
console.log('Available themes:', themes);
console.log('Count:', themes.length);

// Verify each theme loads and has all required tokens
const requiredTokens = [
  '--bg-color', '--bg-secondary', '--text-primary', '--text-secondary', '--text-muted',
  '--accent-color', '--accent-hover', '--link-bg', '--link-bg-hover', '--link-border',
  '--link-radius', '--link-padding', '--font-body', '--font-mono', '--avatar-radius',
  '--page-max-width', '--footer-opacity'
];

const requiredSelectors = [
  'body', '.profile', '.profile__avatar', '.profile__name', '.profile__bio',
  '.links', '.links__item', '.links__anchor', '.links__anchor:hover',
  '.links__label', '.links__icon', '.links__description', '.footer', '.footer__link'
];

for (const name of themes) {
  const css = loadTheme(name);
  console.log(\`\n--- \${name} (\${css.length} bytes) ---\`);

  // Check tokens
  const missingTokens = requiredTokens.filter(t => !css.includes(t));
  if (missingTokens.length) {
    console.log('  MISSING TOKENS:', missingTokens);
  } else {
    console.log('  ✓ All 17 tokens present');
  }

  // Check selectors
  const missingSelectors = requiredSelectors.filter(s => !css.includes(s));
  if (missingSelectors.length) {
    console.log('  MISSING SELECTORS:', missingSelectors);
  } else {
    console.log('  ✓ All selectors present');
  }

  // Check reset
  if (css.includes('box-sizing: border-box')) {
    console.log('  ✓ CSS reset present');
  } else {
    console.log('  MISSING: CSS reset');
  }
}
"

